#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n;
        scanf("%d", &n);
        int *h = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; ++i) scanf("%d", &h[i]);
        int *ans = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; ++i) ans[i] = -1;
        int *stack = (int*)malloc(n * sizeof(int));
        int top = -1;
        for (int i = 0; i < n; ++i) {
            while (top != -1 && h[i] > h[stack[top]]) {
                ans[stack[top--]] = h[i];
            }
            stack[++top] = i;
        }
        for (int i = 0; i < n; ++i) {
            printf("%d", ans[i]);
            if (i + 1 < n) printf(" ");
        }
        printf("\n");
        free(h);
        free(ans);
        free(stack);
    }
    return 0;
}

