let pos = 0;
if (data.length === 0) process.exit(0);
const T = parseInt(data[pos++], 10);
let outputs = [];
for (let tc = 0; tc < T; ++tc) {
  const n = parseInt(data[pos++], 10);
  const h = new Array(n);
  for (let i = 0; i < n; ++i) h[i] = parseInt(data[pos++], 10);
  const ans = new Array(n).fill(-1);
  const stack = [];
  for (let i = 0; i < n; ++i) {
    while (stack.length && h[i] > h[stack[stack.length - 1]]) {
      const idx = stack.pop();
      ans[idx] = h[i];
    }
    stack.push(i);
  }
  outputs.push(ans.join(' '));
}
